      where: { hash_in: $trapdoors, owner: $owner }
      first: $first
      orderBy: id
      orderDirection: desc
    ) {
      id
      fact {
        id
        encryptedBlob
        encryptedEmbedding
        decayScore
        timestamp
        isActive
        contentFp
        sequenceId
        version
      }
    }
  }

